// Parses the "New subscription confirmation" email from receipt@trainingpeaks.com
const results = [];

for (const item of $input.all()) {
  // Collapse all whitespace/line-wraps so multi-line fields become single-line before matching
  const flat = (item.json.textPlain || '').replace(/\s+/g, ' ').trim();

  const nameEmail = flat.match(/Customer Name:\s*([^(]+?)\s*\(([^)]+)\)/i);
  const subMatch = flat.match(/Subscription:\s*([\s\S]+?)\s-\s\$/);
  const invoiceMatch = flat.match(/Invoice Number:\s*(\S+)/i);
  const amountMatch = flat.match(/Amount Charged:\s*\$([\d.,]+)/i);

  const fullName = nameEmail ? nameEmail[1].trim() : '';
  const nameParts = fullName.split(/\s+/);
  const lastname = nameParts.pop() || '';
  const firstname = nameParts.join(' ');

  results.push({
    json: {
      firstname,
      lastname,
      email: nameEmail ? nameEmail[2].trim() : '',
      subscription_name: subMatch ? subMatch[1].trim() : '',
      invoice_number: invoiceMatch ? invoiceMatch[1] : '',
      amount_charged: amountMatch ? amountMatch[1] : '',
      source_subject: item.json.subject,
      source_date: item.json.date,
    }
  });
}

return results;

// Detects which All-Access product (ES/EN/PT) this is from the confirmed real
// product names in TP Payments (see triaperformance-pricing-and-positioning.md).
// Falls back to null + a flag if the product name doesn't match any known one
// (e.g. if the EN product ever gets renamed -- it's the only renameable one).

function detectLanguage(subscriptionName) {
  const s = (subscriptionName || '').toLowerCase();
  if (s.includes('suscripci') && s.includes('triaperformance')) return 'SPANISH';
  if (s.includes('full access')) return 'ENGLISH';
  if (s.includes('acesso total')) return 'PORTUGUESE';
  return null;
}

const results = [];

for (const item of $input.all()) {
  const d = item.json;
  const preferredLanguage = detectLanguage(d.subscription_name);

  results.push({
    json: {
      firstname: d.firstname,
      lastname: d.lastname,
      email: d.email,
      subscription_name: d.subscription_name,
      invoice_number: d.invoice_number,
      amount_charged: d.amount_charged,
      preferredLanguage, // null if unrecognized -- check Telegram alert if so
      language_unrecognized: preferredLanguage === null,
    }
  });
}

return results;

