// Parses the "Subscription cancellation" (confirmed, not "scheduled") email
const results = [];

for (const item of $input.all()) {
  const flat = (item.json.textPlain || '').replace(/\s+/g, ' ').trim();

  const m = flat.match(/that\s+(.+?)'s\s*\(([^)]+)\)\s+subscription to\s+(.+?)\s+has been cancelled/i);

  const fullName = m ? m[1].trim() : '';
  const nameParts = fullName.split(/\s+/);
  const lastname = nameParts.pop() || '';
  const firstname = nameParts.join(' ');

  results.push({
    json: {
      firstname,
      lastname,
      email: m ? m[2].trim() : '',
      subscription_name: m ? m[3].trim() : '',
      source_subject: item.json.subject,
      source_date: item.json.date,
    }
  });
}

return results;

